 10	// projectRunOutHours returns the hours projected until current headroom is used
 11	// based on the last-24-hour slope of the bucket series. Returns 0 when the
 12	// slope is non-positive, headroom is gone/unknown, or the series is too
 13	// short to estimate.
 14	func projectRunOutHours(buckets []agent.UsageBucket, remaining float64) float64 {
 15		if len(buckets) < 2 {
 16			return 0
 17		}
 18		// Last 24 hours of buckets; if series is bucketed in 4h blocks, that's 6
 19		// buckets; 1h buckets gives 24.
 20		n := 24
 21		if n > len(buckets) {
 22			n = len(buckets)
 23		}
 24		tail := buckets[len(buckets)-n:]
 25		tokens := make([]float64, len(tail))
 26		for i, b := range tail {
 27			tokens[i] = float64(b.Tokens)
 28		}
 29		perBucket := agent.LinearSlope(tokens)
 30		// Convert slope-per-bucket to slope-per-hour.
 31		var bucketHours float64
 32		if len(tail) >= 2 {
 33			bucketHours = tail[1].Start.Sub(tail[0].Start).Hours()
 34		}
 35		if bucketHours <= 0 {
 36			bucketHours = 1
 37		}
 38		perHour := perBucket / bucketHours
 39		if perHour <= 0 {
 40			return 0
 41		}
 42		if remaining <= 0 {
 43			return 0
 44		}
 45		hours := remaining / perHour
 46		if hours <= 0 {
 47			return 0
 48		}
 49		return hours
 50	}
