 52	func sumTailTokens(buckets []agent.UsageBucket, maxBuckets int) int {
 53		if maxBuckets <= 0 || len(buckets) == 0 {
 54			return 0
 55		}
 56		if maxBuckets > len(buckets) {
 57			maxBuckets = len(buckets)
 58		}
 59		total := 0
 60		for _, b := range buckets[len(buckets)-maxBuckets:] {
 61			total += b.Tokens
 62		}
 63		return total
 64	}
