 74	func refreshProviderStatuses(workDir string) {
 75		providerStatusCache.Lock()
 76		if providerStatusCache.inFlight[workDir] {
 77			providerStatusCache.Unlock()
 78			return
 79		}
 80		providerStatusCache.inFlight[workDir] = true
 81		providerStatusCache.Unlock()
 82	
 83		go func() {
 84			defer func() {
 85				providerStatusCache.Lock()
 86				delete(providerStatusCache.inFlight, workDir)
 87				providerStatusCache.Unlock()
 88			}()
 89			ctx, cancel := context.WithTimeout(context.Background(), 8*time.Second)
 90			defer cancel()
 91			providers, err := liveProviderInfos(ctx, workDir)
 92			if err != nil {
 93				return
 94			}
 95			rows := providerStatusesFromInfos(providers, nil, time.Now().UTC())
 96			storeProviderRows(workDir, rows)
 97		}()
 98	}
