187	// buildSparkline returns a 24-element slice of hourly token totals for the
188	// last 24 hours (oldest-first). Returns nil when fewer than 6 of the 24
189	// hourly buckets have non-zero token counts — the UI uses that floor to
190	// suppress noisy single-spike sparklines (FEAT-014 AC 2: "Sparkline renders
191	// when ≥6 hourly buckets of usage are available").
192	func buildSparkline(entries []agent.SessionIndexEntry, name string, kind agent.UsageMatchKind, now time.Time) []int {
193		if len(entries) == 0 {
194			return nil
195		}
196		buckets := agent.BucketUsage(entries, name, kind, now, 1, time.Hour)
197		totals := make([]int, len(buckets))
198		nonEmpty := 0
199		for i, b := range buckets {
200			totals[i] = b.Tokens
201			if b.Tokens > 0 {
202				nonEmpty++
203			}
204		}
205		if nonEmpty < 6 {
206			return nil
207		}
208		return totals
209	}
