280	// quotaFromHarnessInfo derives a ProviderQuota from the upstream HarnessInfo.
281	// When a rate-limit signal has been captured for this harness (via
282	// RecordHarnessRateLimit — typically on the server's harness-dispatch path
283	// after parsing response headers with agent.ParseRateLimitHeaders), that
284	// signal takes precedence because it carries absolute token ceilings. The
285	// upstream HarnessInfo.Quota only exposes percent-used windows without an
286	// absolute ceiling. Returns nil when nothing usable is published.
287	func quotaFromHarnessInfo(info agentlib.HarnessInfo) *ProviderQuota {
288		if sig, ok := LookupHarnessRateLimit(info.Name); ok {
289			if q := QuotaFromRateLimitSignal(sig); q != nil {
290				return q
291			}
292		}
293		if info.Quota == nil {
294			return nil
295		}
296		return quotaFromState(info.Quota)
297	}
