299	// quotaFromState derives a ProviderQuota from an upstream QuotaState. The
300	// upstream QuotaWindow doesn't expose absolute token ceilings (only percent
301	// used), so we surface the window length and reset time only. Ceiling and
302	// remaining stay unknown unless a harness-specific rate-limit-header path
303	// populates them via QuotaFromRateLimitSignal.
304	func quotaFromState(state *agentlib.QuotaState) *ProviderQuota {
305		if state == nil || len(state.Windows) == 0 {
306			return nil
307		}
308		var windowSeconds int
309		var resetAt string
310		for _, w := range state.Windows {
311			if strings.EqualFold(w.LimitID, "extra") {
312				continue
313			}
314			if windowSeconds == 0 && w.WindowMinutes > 0 {
315				windowSeconds = w.WindowMinutes * 60
316			}
317			if resetAt == "" {
318				if w.ResetsAt != "" {
319					resetAt = w.ResetsAt
320				} else if w.ResetsAtUnix > 0 {
321					resetAt = time.Unix(w.ResetsAtUnix, 0).UTC().Format(time.RFC3339)
322				}
323			}
324			if windowSeconds > 0 && resetAt != "" {
325				break
326			}
327		}
328		if windowSeconds == 0 && resetAt == "" {
329			return nil
330		}
331		q := &ProviderQuota{}
332		if windowSeconds > 0 {
333			v := windowSeconds
334			q.CeilingWindowSeconds = &v
335		}
336		if resetAt != "" {
337			v := resetAt
338			q.ResetAt = &v
339		}
340		return q
341	}
