343	// QuotaFromRateLimitSignal produces a ProviderQuota from a parsed rate-limit
344	// header signal (see agent.ParseRateLimitHeaders). Exposed for future call
345	// sites where the server captures harness response headers.
346	func QuotaFromRateLimitSignal(sig agent.RateLimitSignal) *ProviderQuota {
347		if !sig.HasAny() {
348			return nil
349		}
350		q := &ProviderQuota{}
351		if sig.CeilingTokens >= 0 {
352			v := sig.CeilingTokens
353			q.CeilingTokens = &v
354		}
355		if sig.CeilingWindowSeconds >= 0 {
356			v := sig.CeilingWindowSeconds
357			q.CeilingWindowSeconds = &v
358		}
359		if sig.Remaining >= 0 {
360			v := sig.Remaining
361			q.Remaining = &v
362		}
363		if !sig.ResetAt.IsZero() {
364			v := sig.ResetAt.UTC().Format(time.RFC3339)
365			q.ResetAt = &v
366		}
367		return q
368	}
